#!/usr/bin/env python3
"""Translate large.json DDD spec to MetaEngine generate_code spec."""
import json
import re
from pathlib import Path

SPEC_IN = Path("<benchmark>/spec/large.json")
SPEC_OUT = Path("/tmp/me_python_spec.json")

PRIMITIVE_MAP = {
    "string": "String",
    "number": "Number",
    "boolean": "Boolean",
    "Date": "Date",
}


def kebab(name: str) -> str:
    s = re.sub(r"(?<!^)(?=[A-Z])", "-", name).lower()
    return s


def field_to_param(field):
    p = {"name": field["name"]}
    t = field["type"]
    if t in PRIMITIVE_MAP:
        p["primitiveType"] = PRIMITIVE_MAP[t]
    else:
        # type identifier reference
        p["typeIdentifier"] = kebab(t)
    return p


def parse_return_type(ret_type, agg_name):
    """Return (python_return_type_str, template_refs_for_return)."""
    refs = []
    agg_id = kebab(agg_name)
    # plain Aggregate
    if ret_type == agg_name:
        return f"${agg_id.replace('-', '_')}", [
            {"placeholder": f"${agg_id.replace('-', '_')}", "typeIdentifier": agg_id}
        ]
    # Aggregate | null
    if ret_type == f"{agg_name} | null":
        ph = f"${agg_id.replace('-', '_')}"
        return f"Optional[{ph}]", [{"placeholder": ph, "typeIdentifier": agg_id}]
    # Aggregate[]
    if ret_type == f"{agg_name}[]":
        ph = f"${agg_id.replace('-', '_')}"
        return f"list[{ph}]", [{"placeholder": ph, "typeIdentifier": agg_id}]
    # void
    if ret_type == "void":
        return "None", []
    # primitives
    if ret_type == "string":
        return "str", []
    if ret_type == "number":
        return "float", []
    if ret_type == "boolean":
        return "bool", []
    return "Any", []


def parse_param_type(p_type, agg_name):
    """Return (python_param_type_str, template_refs_for_param)."""
    if p_type == "string":
        return "str", []
    if p_type == "number":
        return "float", []
    if p_type == "boolean":
        return "bool", []
    if p_type == f"Partial<{agg_name}>":
        return "dict", []
    if p_type == agg_name:
        agg_id = kebab(agg_name)
        ph = f"${agg_id.replace('-', '_')}"
        return ph, [{"placeholder": ph, "typeIdentifier": agg_id}]
    return "Any", []


def find_agg_name(types):
    for t in types:
        if t.get("kind") == "aggregate":
            return t["name"]
    return None


def merge_refs(refs_list):
    seen = set()
    out = []
    for refs in refs_list:
        for r in refs:
            key = (r["placeholder"], r["typeIdentifier"])
            if key in seen:
                continue
            seen.add(key)
            out.append(r)
    return out


def build_method_code(method, agg_name):
    name = method["name"]
    params_src = []
    refs_collected = []
    for p in method.get("params", []):
        py_type, refs = parse_param_type(p["type"], agg_name)
        params_src.append(f"{p['name']}: {py_type}")
        refs_collected.append(refs)
    ret_str, ret_refs = parse_return_type(method["returns"], agg_name)
    refs_collected.append(ret_refs)
    params_joined = ", ".join(["self"] + params_src)
    code = (
        f"def {name}({params_joined}) -> {ret_str}:\n"
        f"    raise NotImplementedError('not implemented')"
    )
    return {"code": code, "templateRefs": merge_refs(refs_collected)}


def build_spec(input_spec):
    classes = []
    enums = []
    for domain in input_spec["domains"]:
        dname = domain["name"]
        agg_name = find_agg_name(domain["types"])
        for t in domain["types"]:
            kind = t["kind"]
            tname = t["name"]
            tid = kebab(tname)
            if kind == "enum":
                enums.append({
                    "name": tname,
                    "typeIdentifier": tid,
                    "path": f"{dname}/enums",
                    "comment": f"{tname} enum.",
                    "members": t["members"],
                })
            elif kind == "aggregate":
                params = [field_to_param(f) for f in t["fields"]]
                classes.append({
                    "name": tname,
                    "typeIdentifier": tid,
                    "path": f"{dname}/aggregates",
                    "comment": f"{tname} aggregate root for the {dname} domain.",
                    "constructorParameters": params,
                })
            elif kind == "value_object":
                params = [field_to_param(f) for f in t["fields"]]
                classes.append({
                    "name": tname,
                    "typeIdentifier": tid,
